#include <iostream>
#include <fstream>
#include <vector>
#include <list>
#include <set>

using namespace std;

ifstream fin("supercomputer.in");
ofstream fout("supercomputer.out");

/**
 * @brief solving function of the task using Kahn's algorithm
 * 
 * @param q - set replacing the queue in topsort
 * @param datas - the data sets of the nodes
 * @param indegree - the indegree of the nodes
 * @param adj - the adjacency list
 * @param start_point - the starting point of the topsort (1 or 2)
 * @return int - the minimum number of context switches
 */
int solution(set<pair<int, int>> q, vector<int> datas, vector<int> indegree,
			 list<int> adj[], int start_point) {
	int ans = 0;  // the variable containing the answer

	while (!q.empty()) {  // while the queue is not empty
		if (start_point == 1) {  // based on the starting point
			auto tmp = *q.begin();  // get the first element of the queue

			if (tmp.first == 2) {  // if the first element has a data set of 2
				ans++;  // increment the answer as a context switch is needed
				start_point = 2;  // change the starting point and redo loop
			} else {  // else go on with the topsort
				int node = tmp.second;

				q.erase(q.begin());

				for (auto neigh : adj[node]) {
					indegree[neigh]--;

					if (indegree[neigh] == 0) {
						q.insert(make_pair(datas[neigh], neigh));
					}
				}
			}
		} else {  // same as above but for the second starting point
			auto tmp = *q.rbegin();

			if (tmp.first == 1) {
				ans++;
				start_point = 1;
			} else {
				int node = tmp.second;

				q.erase(prev(q.end()));

				for (auto neigh : adj[node]) {
					indegree[neigh]--;

					if (indegree[neigh] == 0) {
						q.insert(make_pair(datas[neigh], neigh));
					}
				}
			}
		}
	}

	return ans;
}

int main() {
	int n, m;

	fin >> n >> m;

	// the data sets of the nodes to be read
	vector<int> datas(n + 1, 0);

	for (int i = 0; i < n; i++) {
		int x;
		fin >> x;

		datas[i + 1] = x;
	}

	// the adjacency list
	list<int> adj[n + 1];

	for (int i = 0; i < m; i++) {
		int node1, node2;
		fin >> node1 >> node2;

		adj[node1].push_back(node2);
	}

	// the indegree of the nodes
	vector<int> in_degree(n + 1, 0);

	for (int i = 1; i <= n; i++) {
		for (auto neigh : adj[i]) {
			in_degree[neigh]++;
		}
	}

	// queue in topsort having on the first position the data set of the node
	// and on the second position the node itself (sorted by data set)
	set<pair<int, int>> q;

	// insert the nodes with indegree 0 in the queue
	for (int i = 1; i <= n; i++) {
		if (in_degree[i] == 0) {
			q.insert(make_pair(datas[i], i));
		}
	}

	// the answer is the minimum between the two topsorts starting from 1 and 2
	fout << min(solution(q, datas, in_degree, adj, 1),
				solution(q, datas, in_degree, adj, 2)) << "\n";

	return 0;
}

package src.supercomputer;

import java.io.BufferedReader;
import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.io.Reader;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.StringTokenizer;


public class Supercomputer {
	static List<Task> tasks;
	static class Task {
		int id;
		int dataSet;
		List<Integer> dependencies;

		public Task(int id, int dataSet) {
			this.id = id;
			this.dataSet = dataSet;
			this.dependencies = new ArrayList<>();
		}
	}

	public static void main(String[] args) {
		try {
			readInput();

			// Find the minimum number of context switches required
			int contextSwitches = findMinimumContextSwitches(tasks);

			// Write the output to the file "supercomputer.out"
			writeOutput(contextSwitches);

			System.out.println("Output file generated successfully.");
		} catch (FileNotFoundException e) {
			e.printStackTrace();
		}
	}

	public static void readInput() throws FileNotFoundException {
		tasks = new ArrayList<>();
		MyScanner scanner = new MyScanner(new FileReader("supercomputer.in"));

		// read the number of tasks (N) and the number of dependencies (M)
		int N = scanner.nextInt();
		int M = scanner.nextInt();

		// read the dataSet for each task and create Task objects
		for (int i = 0; i < N; i++) {
			int dataSet = scanner.nextInt();
			tasks.add(new Task(i + 1, dataSet));
		}

		// read the dependency information and add dependencies to each task
		for (int i = 0; i < M; i++) {
			int u = scanner.nextInt();
			int v = scanner.nextInt();
			tasks.get(u - 1).dependencies.add(v);
		}
	}

	public static int findMinimumContextSwitches(List<Task> tasks) {
		int N = tasks.size();
		int[] inDegree = new int[N + 1]; // inDegree[i] = number of incoming edges for task i
		int[] dataSetMap = new int[N + 1]; // dataSetMap[i] = dataSet of task i

		// build the in-degree array and dataSetMap
		for (Task task : tasks) {
			dataSetMap[task.id] = task.dataSet;
			for (int dependent : task.dependencies) {
				inDegree[dependent]++;
			}
		}

		// build the topological order
		int[] dist = new int[N + 1];
		Arrays.fill(dist, Integer.MIN_VALUE);
		dist[0] = 0;
		Queue<Integer> queue = new LinkedList<>();
		for (int i = 1; i <= N; i++) {
			// add tasks with no dependencies to the queue and set their distance to 0
			if (inDegree[i] == 0) {
				queue.offer(i);
				dist[i] = 0;
			}
		}

		// perform a BFS on the graph
		while (!queue.isEmpty()) {
			int taskId = queue.poll();
			Task task = tasks.get(taskId - 1);

			// update the distance of dependent tasks and decrement their in-degree
			for (int dependent : task.dependencies) {
				if (dist[taskId] >= dist[dependent]) {
					// if the datasets are different, increment the distance by 1
					if (task.dataSet != tasks.get(dependent - 1).dataSet) {
						dist[dependent] = dist[taskId] + 1;
					} else {
						dist[dependent] = dist[taskId];
					}
				}
				inDegree[dependent]--;

				// add tasks with no remaining dependencies to the queue
				if (inDegree[dependent] == 0) {
					queue.offer(dependent);
				}
			}
		}

		// find the maximum distance, which represents the minimum number of context switches
		int contextSwitches = Arrays.stream(dist).max().getAsInt();

		return contextSwitches;
	}

	public static void writeOutput(int contextSwitches) throws FileNotFoundException {
		PrintWriter writer = new PrintWriter(new File("supercomputer.out"));
		writer.println(contextSwitches);
		writer.close();
	}

	// Code from "Nostory" skel code from Homework 1
	private static class MyScanner {
		private BufferedReader br;
		private StringTokenizer st;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}

		public long nextLong() {
			return Long.parseLong(next());
		}

		public double nextDouble() {
			return Double.parseDouble(next());
		}

		public String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}
	}
}
